@page "/board"
@using sv_d053830561a145c2864f92ac51a7eb94.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (_loading)
{
    <p><em>Loading tasks…</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Summary Stats Bar -->
    <div class="d-flex gap-3 mb-3 flex-wrap">
        <span class="badge bg-secondary fs-6">Total: @_allTasks.Count</span>
        <span class="badge bg-info fs-6">To Do: @GetColumnTasks("To Do").Count</span>
        <span class="badge bg-warning text-dark fs-6">In Progress: @GetColumnTasks("In Progress").Count</span>
        <span class="badge bg-success fs-6">Done: @GetColumnTasks("Done").Count</span>
        <span class="badge bg-danger fs-6">Overdue: @_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="mb-3" style="max-width: 400px;">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="d-flex gap-3 align-items-start">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="card flex-fill" style="min-width: 280px;">
                <div class="card-header fw-bold">
                    @column <span class="badge bg-secondary ms-2">@tasks.Count</span>
                </div>
                <div class="card-body p-2" style="min-height: 200px;">
                    @foreach (var task in tasks)
                    {
                        <div class="card mb-2">
                            <div class="card-body p-2">
                                <h6 class="card-title mb-1">@task.Title</h6>
                                <p class="card-text mb-1 text-muted small">@task.Assignee</p>
                                <span class="badge @GetPriorityClass(task.Priority) me-1">@task.Priority</span>
                                <span class="text-muted small">@task.DueDate.ToString("MMM dd")</span>
                                <div class="mt-2 d-flex gap-1">
                                    @if (GetColumnIndex(column) > 0)
                                    {
                                        <button class="btn btn-outline-secondary btn-sm"
                                                @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) - 1])">
                                            ← Move Left
                                        </button>
                                    }
                                    @if (GetColumnIndex(column) < _columns.Length - 1)
                                    {
                                        <button class="btn btn-outline-secondary btn-sm"
                                                @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) + 1])">
                                            Move Right →
                                        </button>
                                    }
                                </div>
                            </div>
                        </div>
                    }

                    <!-- Inline Add Task Form -->
                    @if (_addingToColumn == column)
                    {
                        <div class="card border-primary mb-2">
                            <div class="card-body p-2">
                                <input type="text" class="form-control form-control-sm mb-1"
                                       placeholder="Title" @bind="_newTitle" />
                                <input type="text" class="form-control form-control-sm mb-1"
                                       placeholder="Assignee" @bind="_newAssignee" />
                                <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                    <option value="High">High</option>
                                    <option value="Medium">Medium</option>
                                    <option value="Low">Low</option>
                                </select>
                                <input type="date" class="form-control form-control-sm mb-2"
                                       @bind="_newDueDate" />
                                <div class="d-flex gap-1">
                                    <button class="btn btn-primary btn-sm" @onclick="SaveNewTask">Save</button>
                                    <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">Cancel</button>
                                </div>
                            </div>
                        </div>
                    }
                </div>
                <div class="card-footer p-2">
                    <button class="btn btn-outline-primary btn-sm w-100"
                            @onclick="() => StartAdd(column)">
                        + Add Task
                    </button>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText) ||
                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns a task with default status; update to match the target column
            if (created.Status != _addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

